/**
 * @param {number} n
 * @return {number[]}
 */
function solve(n) {
    // Map to store the sums (x = a^3 + b^3) and the count of distinct pairs (a, b) that yield this sum.
    // Key: sum x
    // Value: Set of pairs (a, b) that result in x. Since we only care about the count >= 2, 
    // we can simplify by just counting how many pairs yield the sum.
    const sums = new Map();

    // Determine the maximum value for a and b.
    // Since a^3 + b^3 <= n and a <= b, then 2 * b^3 >= n, so b^3 >= n/2.
    // Also, since a >= 1, b^3 <= n - 1. So b <= n^(1/3).
    // A safe upper bound for b is ceil(n^(1/3)).
    // Since n <= 10^9, n^(1/3) <= 1000.

    // Max b such that b^3 <= n
    let maxB = Math.floor(Math.pow(n, 1/3));

    // Since a >= 1, and a <= b, the smallest possible sum is 1^3 + 1^3 = 2.

    // Iterate over all possible values for a
    for (let a = 1; ; a++) {
        // a^3 must be less than n
        const aCubed = a * a * a;
        if (aCubed >= n) {
            break;
        }

        // Iterate over all possible values for b, starting from a
        for (let b = a; ; b++) {
            const bCubed = b * b * b;
            const sum = aCubed + bCubed;

            if (sum > n) {
                break; // Since b is increasing, further sums will also exceed n
            }

            // Check if this sum has been seen before
            if (!sums.has(sum)) {
                sums.set(sum, new Set());
            }

            // Store the pair (a, b) that generated this sum. 
            // Using a Set ensures we only count distinct pairs if the iteration structure allowed duplicates, 
            // but given a <= b and the loops structure, (a, b) is unique for a given sum calculation order.
            // We just need to ensure the count reaches 2.
            sums.get(sum).add(`${a},${b}`);
        }
    }

    const result = [];
    for (const [sum, pairs] of sums.entries()) {
        // A "good integer" exists if there are at least two different pairs (a, b).
        if (pairs.size >= 2) {
            result.push(sum);
        }
    }

    // Return the results sorted in ascending order.
    result.sort((a, b) => a - b);

    return result;
}

