            // Since we iterate with a <= b, each pair (a, b) is unique in the order it's generated.
            // We simply increment the count for this sum.
            sums_count[sum]++;

            // Optimization: If we already found 2 pairs, we don't need to count more pairs for this sum 
            // *in the context of this loop structure* if we only needed to know if count >= 2. 
            // However, since we need *all* good integers, we must continue generating sums up to n.
        }
