#include <vector>
#include <map>
#include <set>
#include <algorithm>
#include <cmath>

using namespace std;

/**
 * @brief Finds all "good integers" less than or equal to n.
 * 
 * A good integer x is one that can be represented as the sum of two positive cubes (a^3 + b^3) 
 * in at least two different ways, where a <= b.
 * 
 * @param n The upper bound.
 * @return std::vector<long long> A sorted list of all good integers <= n.
 */
std::vector<long long> solve(long long n) {
    // Map to store the sums (x = a^3 + b^3) and the count of distinct pairs (a, b) that yield this sum.
    // Key: sum x
    // Value: count of distinct pairs (a, b)
    std::map<long long, int> sum_counts;

    // Determine the maximum value for b. Since a >= 1 and a <= b, 2*b^3 >= a^3 + b^3 <= n.
    // So, b^3 <= n, thus b <= n^(1/3).
    // We use a slightly safer upper bound based on n/2 for initial estimation, but the inner loop check is key.
    long long max_b_limit = (long long)std::cbrt(n) + 2; 

    // Iterate over all possible values for a
    for (long long a = 1; ; ++a) {
        long long a_cubed = a * a * a;
        if (a_cubed >= n) {
            break;
        }

        // Iterate over all possible values for b, starting from a
        for (long long b = a; ; ++b) {
            long long b_cubed = b * b * b;
            long long sum = a_cubed + b_cubed;

            if (sum > n) {
                break; // Since b is increasing, further sums will also exceed n
            }

            // We found a representation for 'sum'. Increment its count.
            sum_counts[sum]++;
        }
    }

    std::vector<long long> result;
    for (const auto& pair : sum_counts) {
        long long sum = pair.first;
        int count = pair.second;

        // A "good integer" exists if there are at least two different pairs (a, b).
        if (count >= 2) {
            result.push_back(sum);
        }
    }

    // The map iterates in ascending key order, so the result vector should naturally be sorted.
    // However, an explicit sort guarantees correctness regardless of map implementation details 
    // if we were to use std::unordered_map, but since we use std::map, it's sorted by key (sum).
    // We keep it simple as the map ensures order.

    return result;
}

